interviewQuestions.answer:
A microtask that queues itself recursively: <pre><code>function starve() {
  queueMicrotask(() => {
    console.log('microtask');
    starve(); // queues another microtask
  });
}
starve();
setTimeout(() => console.log('macrotask'), 0);
// The setTimeout callback NEVER runs</code></pre>This keeps the Microtask Queue non-empty forever, so macrotasks are never processed.

codeExamples.code:
console.log('Start');

// Schedule a microtask explicitly
queueMicrotask(() => {
  console.log('Microtask: runs after sync, before macrotasks');
});

setTimeout(() => {
  console.log('Macrotask: runs after microtasks');
}, 0);

console.log('End');

// Output:
// Start
// End
// Microtask: runs after sync, before macrotasks
// Macrotask: runs after microtasks

setTimeout(() => console.log('1 - macrotask'), 0);

Promise.resolve().then(() => {
  console.log('2 - Promise.then');
});

queueMicrotask(() => {
  console.log('3 - queueMicrotask');
});

// Microtasks that queue more microtasks
Promise.resolve().then(() => {
  console.log('4 - Promise.then that queues another');
  queueMicrotask(() => {
    console.log('5 - nested microtask still in same cycle');
  });
});

console.log('6 - sync');

// Output:
// 6 - sync
// 2 - Promise.then
// 3 - queueMicrotask
// 4 - Promise.then that queues another
// 5 - nested microtask still in same cycle
// 1 - macrotask

// Note: 5 runs BEFORE 1, proving the entire microtask queue is drained

// Microtask error
queueMicrotask(() => {
  throw new Error('Microtask error');
});

// Macrotask error
setTimeout(() => {
  throw new Error('Macrotask error');
}, 0);

console.log('Sync code runs');

// Both errors are caught by window.onerror or process.on('uncaughtException')
// But the microtask error will be detected FIRST (before setTimeout)
// However, if a microtask error goes unhandled:
// - Node.js: process.on('unhandledRejection') for Promise, 
//   process.on('uncaughtException') for queueMicrotask
// - Browser: window.onerror for both

// Fix microtask errors with try/catch:
queueMicrotask(() => {
  try {
    throw new Error('Caught error');
  } catch (e) {
    console.log('Handled:', e.message);
  }
});

// Create an observer
const observer = new MutationObserver((mutations) => {
  console.log('Mutation observed:', mutations.length, 'changes');
  console.log('This runs as a MICROTASK');
});

// Start observing
target = document.getElementById('target');
observer.observe(target, { childList: true });

// Make a change
target.textContent = 'New text';
// MutationObserver callback is scheduled as a microtask

console.log('After mutation (sync)');

Promise.resolve().then(() => {
  console.log('Promise.then (also microtask)');
});

setTimeout(() => {
  console.log('setTimeout (macrotask)');
}, 0);

// Output:
// After mutation (sync)
// Mutation observed: 1 changes
// Promise.then (also microtask)
// setTimeout (macrotask)

// Note: MutationObserver and Promise.then are in the same microtask queue
// Their relative order depends on which was queued first

async function demo() {
  console.log('1 - async function starts (sync)');

  await Promise.resolve();
  // The rest of this function is a MICROTASK continuation

  console.log('3 - after await (microtask)');
}

demo();

console.log('2 - sync after calling demo');

setTimeout(() => {
  console.log('5 - setTimeout (macrotask)');
}, 0);

Promise.resolve().then(() => {
  console.log('4 - Promise.then (microtask)');
});

console.log('2.5 - more sync');

// Output:
// 1 - async function starts (sync)
// 2 - sync after calling demo
// 2.5 - more sync
// 3 - after await (microtask)
// 4 - Promise.then (microtask)
// 5 - setTimeout (macrotask)
